import json
import os
import re
import urllib
from datetime import datetime

from sqlalchemy import create_engine, text

from src.utils.config_utils import ConfigUtils
from src.utils.logging_utils import get_logger, setup_logger

logger = setup_logger("pipeline")

FORMAT_MAPPING = {
    "MMddyyyy": "%m%d%Y",
    "yyyyMMdd": "%Y%m%d",
    "ddMMyyyy": "%d%m%Y",
    "yyMMdd": "%y%m%d",
}

def is_valid_table_name(name: str) -> bool:
    """
    Validate table name to prevent SQL injection.
    Allows table names that start with a letter or underscore,
    followed by letters, digits, or underscores.
    """
    return re.match(r'^[A-Za-z_][A-Za-z0-9_\-]*$', name) is not None
config = ConfigUtils()

def load_column_config(json_path):
    if not os.path.exists(json_path):
        raise FileNotFoundError(f"[ERROR] JSON config file does not exist: {json_path}")
    if os.path.getsize(json_path) == 0:
        raise ValueError(f"[ERROR] JSON config file is empty: {json_path}")

    # Log the file path for debugging
    print(f"Loading JSON config from: {json_path}")
    with open(json_path, "r") as f:
        content = f.read()
        return json.loads(content)


def get_schema_of_table(conn, table_name):
    try:
        result = conn.execute(
            text(
                """
                SELECT s.name
                FROM sys.tables t
                JOIN sys.schemas s ON t.schema_id = s.schema_id
                WHERE t.name = :table_name
            """
            ),
            {"table_name": table_name},
        ).fetchone()
        return result[0] if result else "dbo"
    except Exception as e:
        get_logger().error(f"Could not fetch schema: {str(e)}")
        return "dbo"


def get_max_bulkcopy_ts(conn, schema, table_name):
    try:
        result = conn.execute(
            text(f"SELECT MAX([SqlBulkCopy_TS]) FROM [{schema}].[{table_name}]") # nosec B608 from config
        ).fetchone()
        return result[0] if result else None
    except Exception as e:
        get_logger().warning(f"Could not get max SqlBulkCopy_TS: {str(e)}")
        return None


def get_max_file_date_from_table(
    server, database, table_name, filter_column="FileDate"
):
    conn_str = (
        "DRIVER={ODBC Driver 17 for SQL Server};"
        f"SERVER={server};DATABASE={database};Trusted_Connection=yes;"
    )
    params = urllib.parse.quote_plus(conn_str)
    engine = create_engine(f"mssql+pyodbc:///?odbc_connect={params}")

    with engine.begin() as conn:
        try:
            result = conn.execute(
                text(f"SELECT MAX([{filter_column}]) FROM {table_name}") # nosec B608 table name getting from config source.
            ).scalar()
            return result if result else None
        except Exception as e:
            get_logger().error(
                f"Failed to get MAX({filter_column}) from {table_name}: {e}"
            )
            return None


def bulk_insert_records(
    table_name, records, schema, conn, column_names, batch_size=30000
):
    cursor = conn.connection.cursor()
    cursor.fast_executemany = True

    placeholders = ", ".join(["?" for _ in column_names])
    column_list = ", ".join(f"[{c}]" for c in column_names)

    if not all(map(is_valid_table_name, [schema, table_name] + column_names)):
        raise ValueError("Invalid SQL identifier detected.")

    insert_query = (
        f"INSERT INTO [{schema}].[{table_name}] ({column_list}) VALUES ({placeholders})" # nosec B608
    )

    try:
        for i in range(0, len(records), batch_size):
            batch = records[i : i + batch_size]
            cursor.executemany(insert_query, batch)
            cursor.commit()
            get_logger().info(
                f"Inserted batch {i // batch_size + 1}: {len(batch)} records."
            )
    except Exception as e:
        get_logger().error(f"Bulk insert failed: {str(e)}")
        raise e
    finally:
        cursor.close()


def extract_date_from_filename(filename):
    basename = os.path.basename(filename)

    match_8 = re.search(r"(\d{8})", basename)
    if match_8:
        try:
            parsed = datetime.strptime(match_8.group(1), "%Y%m%d")
            if parsed.year < 1753:
                return None
            return parsed.date()
        except ValueError:
            pass

    match_6 = re.search(r"(\d{6})", basename)
    if match_6:
        raw = match_6.group(1)
        try:
            parsed = datetime.strptime(raw, "%y%m%d")
            if parsed.year < 1753:
                return None
            return parsed.date()
        except ValueError:
            pass

    return None


def upload_fixed_width_to_mssql(
    module_name,
    file_path,
    json_config_path,
    server,
    database,
    table_name,
    column_names,
    metadata_fields=None,
    mode="truncate",
    filter_column="FileDate",
):
    column_config = load_column_config(json_config_path)
    records = []

    if metadata_fields:
        for field in metadata_fields:
            if field not in column_names:
                column_names.append(field)

    file_date = extract_date_from_filename(file_path)

    with open(file_path, "r", encoding="latin1", errors="replace") as f:
        for line in f:
            row_list = []

            for col in column_config:
                start = col["ColumnStartIndex"]
                end = start + col["ColumnLength"]
                raw_value = line[start:end].strip()
                col_type = col.get("ColumnType", "System.String")
                col_format = col.get("ColumnFormat", "")
                col_default = col.get("ColumnDefault", "")

                parsed_value = raw_value or col_default

                try:
                    if col_type == "System.DateTime":
                        fmt = FORMAT_MAPPING.get(col_format, col_format)
                        parsed_value = (
                            datetime.strptime(parsed_value, fmt)
                            if parsed_value
                            else None
                        )
                        if parsed_value and parsed_value.year < 1753:
                            parsed_value = None
                    elif col_type == "System.Int32":
                        parsed_value = int(parsed_value) if parsed_value else 0
                    elif col_type == "System.Decimal":
                        parsed_value = float(parsed_value) if parsed_value else 0.0
                except Exception:
                    parsed_value = None

                row_list.append(parsed_value)

            if metadata_fields:
                if "FileDate" in metadata_fields:
                    row_list.append(file_date)
                if "SqlBulkCopy_TS" in metadata_fields:
                    row_list.append(datetime.now())

            records.append(tuple(row_list))

    conn_str = (
        "DRIVER={ODBC Driver 17 for SQL Server};"
        f"SERVER={server};DATABASE={database};Trusted_Connection=yes;Connection Timeout=120;"
    )
    params = urllib.parse.quote_plus(conn_str)
    engine = create_engine(f"mssql+pyodbc:///?odbc_connect={params}")

    total_inserted = 0
    total_failed = 0

    with engine.begin() as conn:
        schema = get_schema_of_table(conn, table_name)
        full_table = f"[{schema}].[{table_name}]"

        # Append mode: compare file date to max filter_column
        if mode == "append" and file_date:
            result = conn.execute(
                text(f"SELECT MAX([{filter_column}]) FROM {full_table}")  # nosec B608 table name from config
            ).fetchone()
            latest_col_value = result[0] if result else None
            if latest_col_value:
                file_dt_as_datetime = datetime.combine(file_date, datetime.min.time())
                if file_dt_as_datetime <= latest_col_value:
                    msg = (
                        f"Skipped file '{os.path.basename(file_path)}': "
                        f"file date {file_date} is not newer than {filter_column} {latest_col_value.date()}"
                    )
                    get_logger().info(msg)
                    return 0, 0, 0, msg

        if mode == "truncate":
            conn.execute(text(f"TRUNCATE TABLE {full_table}"))

        conn.execute(text(f"ALTER INDEX ALL ON {full_table} DISABLE"))

        batch_size = config.get(module_name, "options.batch_size", 30000)
        if batch_size > 30000:
            batch_size = 30000
        for i in range(0, len(records), batch_size):
            batch = records[i : i + batch_size]
            try:
                bulk_insert_records(table_name, batch, schema, conn, column_names)
                total_inserted += len(batch)
            except Exception as batch_err:
                raise Exception(f"Bulk insert failed: {str(batch_err)}", batch_err)

        conn.execute(text(f"ALTER INDEX ALL ON {full_table} REBUILD"))

    return len(records), total_inserted, total_failed, None

import os

import pytds
import sqlalchemy as sa
from sqlalchemy import event
from sqlalchemy.ext.asyncio import create_async_engine, AsyncEngine
from src.utils.config_utils import ConfigUtils

env = os.getenv("DOH_APP_ENV", "dev")  # Default to 'dev' if not set


class DatabasePoolTarget:
    def __init__(self):
        self.config = ConfigUtils()
        self.target_conn = None
        self.target_async_conn: AsyncEngine = None

    def create_connection(self, module_name):
        try:
            if not self.target_conn:
                target_server = self.config.get(
                    module_name, "destination.connection.url"
                )
                target_db = self.config.get(
                    module_name, "destination.connection.dbname"
                )
                if not target_db:
                    raise Exception(f"Failed to create target DB connection: Invalid target connection details.")
                target_engine = sa.create_engine(
                    f"mssql+pyodbc://@{target_server}/{target_db}?driver=ODBC+Driver+17+for+SQL+Server&trusted_connection=yes",
                    fast_executemany=True,
                    connect_args={"autocommit": True},
                    pool_pre_ping = True,  # checks if connection is alive before using
                    pool_recycle = 1800  # recycle connections every 1 hour
                )
                self.target_conn = target_engine
                print("Target connection created.")

                @event.listens_for(self.target_conn, "before_cursor_execute")
                def set_fast_executemany(
                    conn, cursor, statement, parameters, context, executemany
                ):
                    if executemany:
                        cursor.fast_executemany = True

            return self.target_conn
        except pytds.Error as e:
            raise Exception(f"Failed to create target DB connection: {str(e)}")

    async def create_async_connection(self, module_name)  -> AsyncEngine:
        try:
            if not self.target_async_conn:
                target_server = self.config.get(module_name, "destination.connection.url")
                target_db = self.config.get(module_name, "destination.connection.dbname")

                if not target_db:
                    raise Exception(f"Failed to create target DB connection: Invalid target connection details.")
                # Async connection string using aioodbc
                async_conn_str = (
                    f"mssql+aioodbc://@{target_server}/{target_db}"
                    "?driver=ODBC+Driver+17+for+SQL+Server&trusted_connection=yes"
                )

                self.target_async_conn = create_async_engine(
                    async_conn_str,
                    echo=False,
                    future=True,
                    # pool_pre_ping=True,
                )
                print("Async target connection created.")

            return self.target_async_conn
        except Exception as e:
            raise Exception(f"Failed to create async target DB connection: {str(e)}")

    async def dispose_async_connection(self):
        if self.target_async_conn:
            await self.target_async_conn.dispose()

