                    f"mssql+aioodbc://@{target_server}/{target_db}"
                    "?driver=ODBC+Driver+17+for+SQL+Server&trusted_connection=yes"
                )

                self.target_async_conn = create_async_engine(
                    async_conn_str,
                    echo=False,
                    future=True,
